import 'package:flutter/services.dart';
import 'package:uni_links/uni_links.dart';

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Uni Links Demo',
      onGenerateRoute: (settings) => Navigator.pushNamed(settings.name),
      initialRoute: '/',
      routes: {
        '/': (_) => MyHomePage(),
        '/profile': (_) => ProfilePage(),
        '/payment/confirm': (_) => PaymentConfirmPage(),
      },
    );
  }
}

class MyHomePage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Uni Links Demo'),
      ),
      body: Center(
        child: ElevatedButton(
          onPressed: () async {
            final uri = await getUri();
            if (uri != null && uri.scheme == 'myapp') {
              _handleLink(uri);
            }
          },
          child: Text('Open URL'),
        ),
      ),
    );
  }

  void _handleLink(Uri link) {
    final parameters = Uri.parse(link.toString()).queryParameters;
    if (parameters['id'] != null && int.tryParse(parameters['id']) != null) {
      Navigator.pushNamed(context, '/profile', arguments: parameters['id']);
    } else if (parameters['paymentId'] != null &&
        parameters['paymentStatus'] != null) {
      Navigator.pushNamed(
          context, '/payment/confirm',
          arguments: {'paymentId': parameters['paymentId'], 'paymentStatus': parameters['paymentStatus']});
    }
  }
}

class ProfilePage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final id = ModalRoute.of(context).settings.arguments;
    return Scaffold(
      appBar: AppBar(title: Text('Profile Page')),
      body: Center(child: Text('User ID: $id')),
    );
  }
}

class PaymentConfirmPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final paymentArgs = ModalRoute.of(context).settings.arguments;
    return Scaffold(
      appBar: AppBar(title: Text('Payment Confirmation')),
      body: Center(
        child: Text('Payment ID: ${paymentArgs['paymentId']} Status: ${paymentArgs['paymentStatus']}'),
